"use client";
import { LiaClipboardListSolid } from "react-icons/lia";
import { MdPendingActions } from "react-icons/md";
import { useRouter } from "next/navigation";
export default function AddBlog() {
  const router = useRouter();

  function goHome() {
    router.push("/");
  }
  return (
    <div className="flex h-screen font-sans">
      {/* Sidebar */}
      <div className="w-60 bg-sky-50 p-5 border-r-2 border-gray-300">
        <h2 className="text-2xl font-bold mb-10">Admin Panel</h2>
        <button className="w-full bg-white py-3 px-4 mb-5 border-2 border-black text-left font-semibold hover:bg-gray-100 flex">
        <MdPendingActions className="text-xl"/> Pending blogs
        </button>
        <button className="w-full bg-white py-3 px-4 mb-5 border-2 border-black text-left font-semibold hover:bg-gray-100 flex">
        <LiaClipboardListSolid className="text-xl"/> Blog lists
        </button>
        <button
          onClick={goHome}
          className="w-full bg-black text-white py-3 px-4 rounded-md hover:bg-gray-800 mt-10"
        >
          Go to Homepage
        </button>
      </div>
      <div className="bg-[#fafafa] w-screen">
        welcome to the admin panel 
      </div>
     
    </div>
  );
}
